import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.c3r8iWL8.js";const u=JSON.parse('{"title":"SOP-003: Spec Authoring & Approval","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"sops/SOP-003-spec-approval.md","filePath":"sops/SOP-003-spec-approval.md","lastUpdated":1782929962000}'),i={name:"sops/SOP-003-spec-approval.md"};function s(n,e,l,d,c,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="sop-003-spec-authoring-approval" tabindex="-1">SOP-003: Spec Authoring &amp; Approval <a class="header-anchor" href="#sop-003-spec-authoring-approval" aria-label="Permalink to &quot;SOP-003: Spec Authoring &amp; Approval&quot;">​</a></h1><p><strong>Version:</strong> 1.0 · <strong>Owner:</strong> Architect + PO · <strong>Gate:</strong> G1</p><h2 id="purpose-scope" tabindex="-1">Purpose &amp; scope <a class="header-anchor" href="#purpose-scope" aria-label="Permalink to &quot;Purpose &amp; scope&quot;">​</a></h2><p>Produce an <strong>Approved</strong> OpenAPI (and optional AsyncAPI/BDD) contract that unlocks implementation (SOP-004).</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>RACI</th></tr></thead><tbody><tr><td>ARCH</td><td><strong>A</strong> — API design approval</td></tr><tr><td>PO</td><td><strong>A</strong> — acceptance criteria</td></tr><tr><td>DEV</td><td>R — AI-assisted draft, technical review</td></tr><tr><td>SEC</td><td>C — auth, data exposure</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>SOP-001 complete (tier, acceptance criteria draft)</li><li>Accepted ADRs linked for architectural constraints</li></ul><h2 id="procedure" tabindex="-1">Procedure <a class="header-anchor" href="#procedure" aria-label="Permalink to &quot;Procedure&quot;">​</a></h2><ol><li><strong>Branch</strong> — <code>spec/feature-XXX</code> from <code>main</code>.</li><li><strong>AI draft spec</strong> — From ticket + ADRs, generate OpenAPI 3.1 skeleton: paths, schemas, error model, <code>x-adr</code> refs.</li><li><strong>BDD scenarios</strong> — AI drafts Gherkin for happy path + key edge cases; PO reviews language.</li><li><strong>Set status</strong> — <code>info.x-status: draft</code> → <code>in-review</code> when PR opened.</li><li><strong>Review PR</strong> — ARCH: REST/async design, versioning, breaking change policy. PO: scenarios match intent. SEC: auth scopes if external.</li><li><strong>Contract lint</strong> — CI runs Spectral (or equivalent); zero errors required.</li><li><strong>Approve</strong> — ARCH + PO comment <code>approved</code>; set <code>info.x-status: approved</code>.</li><li><strong>Merge</strong> — Triggers SOP-009; CI applies <code>implementation-unlocked</code> label to linked ticket.</li></ol><h2 id="definition-of-done" tabindex="-1">Definition of Done <a class="header-anchor" href="#definition-of-done" aria-label="Permalink to &quot;Definition of Done&quot;">​</a></h2><ul><li>[ ] <code>info.x-status: approved</code></li><li>[ ] All operations have: summary, error responses, linked ADR IDs where architectural</li><li>[ ] BDD file linked in spec README or <code>x-bdd</code> extension</li><li>[ ] Breaking change section filled if modifying existing API</li><li>[ ] Contract lint CI green</li></ul><h2 id="sla-escalation" tabindex="-1">SLA &amp; escalation <a class="header-anchor" href="#sla-escalation" aria-label="Permalink to &quot;SLA &amp; escalation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Milestone</th><th>SLA</th></tr></thead><tbody><tr><td>Draft → in-review</td><td>≤ 3 business days after intake</td></tr><tr><td>in-review → approved</td><td>≤ 2 business days</td></tr></tbody></table><p>Escalation: PO/ARCH disagreement → EM + weekly ARB.</p><h2 id="related-sops" tabindex="-1">Related SOPs <a class="header-anchor" href="#related-sops" aria-label="Permalink to &quot;Related SOPs&quot;">​</a></h2><ul><li><a href="./SOP-001-feature-intake.html">SOP-001</a> · <a href="./SOP-002-adr-lifecycle.html">SOP-002</a> · <a href="./SOP-004-implementation.html">SOP-004</a> · <a href="./SOP-009-artifact-publish.html">SOP-009</a></li></ul>',17)])])}const f=t(i,[["render",s]]);export{u as __pageData,f as default};
